const fs = require("fs");
const path = require("path");

const ROOT = path.resolve(__dirname, "..");
const PERIOD_ID = "p8";
const PERIOD = "Period 8";
const DATE_RANGE = "1945-1980";
const AP_WEIGHT = "10-17%";

const THEME = {
  politics: "Politics and Power",
  identity: "American and National Identity",
  work: "Work, Exchange, Technology",
  culture: "Culture and Society",
  migration: "Migration and Settlement",
  geography: "Geography and Environment",
  world: "America in the World",
};

function decodeHtml(value) {
  return String(value || "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&rsquo;/g, "'")
    .replace(/&lsquo;/g, "'")
    .replace(/&rdquo;/g, '"')
    .replace(/&ldquo;/g, '"')
    .replace(/&mdash;/g, "-")
    .replace(/&ndash;/g, "-")
    .replace(/&#x([0-9a-f]+);/gi, (_, hex) => String.fromCodePoint(parseInt(hex, 16)))
    .replace(/&#(\d+);/g, (_, num) => String.fromCodePoint(parseInt(num, 10)));
}

function stripTags(value) {
  return decodeHtml(String(value || ""))
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getAttr(tag, name) {
  const normalizedTag = decodeHtml(tag);
  const quoted = normalizedTag.match(new RegExp(`${name}\\s*=\\s*(["'])([\\s\\S]*?)\\1`, "i"));
  if (quoted) return decodeHtml(quoted[2]).trim().replace(/^["']|["']$/g, "");
  const bare = normalizedTag.match(new RegExp(`${name}\\s*=\\s*([^\\s>]+)`, "i"));
  return bare ? decodeHtml(bare[1]).trim().replace(/^["']|["']$/g, "") : "";
}

function getNearbyCaption(html, index) {
  const after = html.slice(index, Math.min(html.length, index + 5000));
  const fig = after.match(/<figcaption[\s\S]*?<\/figcaption>/i);
  if (fig) return stripTags(fig[0]);

  const paragraph = after.match(/<p(?:\s[^>]*)?>[\s\S]*?<\/p>/i);
  if (paragraph) {
    const text = stripTags(paragraph[0]);
    if (text.length > 20 && text.length < 900) return text;
  }

  const before = html.slice(Math.max(0, index - 1500), index);
  const previousParagraphs = [...before.matchAll(/<p(?:\s[^>]*)?>[\s\S]*?<\/p>/gi)];
  if (previousParagraphs.length) {
    const text = stripTags(previousParagraphs[previousParagraphs.length - 1][0]);
    if (text.length > 20 && text.length < 900) return text;
  }

  return "";
}

function extractChapterImages(chapterNum) {
  const textbookDir = path.join(ROOT, "textbook");
  const chapterDir = path.join(textbookDir, `chapter ${chapterNum}`);
  const hasChapterDir = fs.existsSync(chapterDir) && fs.statSync(chapterDir).isDirectory();
  const dir = hasChapterDir ? chapterDir : textbookDir;
  const chapterPattern = new RegExp(`chapter\\s*${chapterNum}`, "i");
  const files = fs.readdirSync(dir)
    .filter((file) => file.toLowerCase().endsWith(".html"))
    .filter((file) => hasChapterDir || chapterPattern.test(file))
    .sort();

  if (files.length === 0) {
    throw new Error(`Missing textbook HTML for chapter ${chapterNum}`);
  }

  const images = [];
  let rawIndex = 0;

  for (const file of files) {
    const html = fs.readFileSync(path.join(dir, file), "utf8");
    const imgRegex = /<img\b[^>]*>/gi;
    let match;
    while ((match = imgRegex.exec(html))) {
      rawIndex += 1;
      images.push({
        rawIndex,
        file,
        src: getAttr(match[0], "src"),
        alt: getAttr(match[0], "alt"),
        caption: getNearbyCaption(html, match.index),
      });
    }
  }

  return images;
}

function hasChapterSource(chapterNum) {
  try {
    extractChapterImages(chapterNum);
    return true;
  } catch (_) {
    return false;
  }
}

function extensionFromDataUrl(src) {
  const type = String(src || "").match(/^data:([^;,]+)[;,]/i)?.[1]?.toLowerCase() || "";
  if (type.includes("png")) return "png";
  if (type.includes("svg")) return "svg";
  if (type.includes("webp")) return "webp";
  return "jpg";
}

function writeImageFile(src, outputBase) {
  const cleaned = String(src || "").trim().replace(/^["']|["']$/g, "");
  const extension = extensionFromDataUrl(cleaned);
  const outputPath = `${outputBase}.${extension}`;

  if (cleaned.startsWith("data:")) {
    const base64 = cleaned.match(/^data:[^;,]+;base64,([\s\S]+)$/i);
    if (base64) {
      fs.writeFileSync(outputPath, Buffer.from(base64[1], "base64"));
    } else {
      const raw = cleaned.replace(/^data:[^,]+,/i, "");
      fs.writeFileSync(outputPath, decodeURIComponent(raw));
    }
  }

  return path.relative(ROOT, outputPath).replace(/\\/g, "/");
}

function slugify(text) {
  return String(text || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function id(num, suffix) {
  return `chapter${num}-${suffix}`;
}

function chapterImageId(num, index) {
  return `chapter${num}-img-${String(index).padStart(3, "0")}`;
}

function materializeImages(spec) {
  const extracted = extractChapterImages(spec.chapterNum);
  const outDir = path.join(ROOT, "images", `chapter${spec.chapterNum}`);
  fs.mkdirSync(outDir, { recursive: true });

  return spec.imageSelections.map((selection, index) => {
    const raw = extracted.find((image) => image.rawIndex === selection.rawIndex);
    if (!raw) {
      throw new Error(`Missing image ${selection.rawIndex} for chapter ${spec.chapterNum}`);
    }

    const imageId = chapterImageId(spec.chapterNum, index + 1);
    const src = writeImageFile(raw.src, path.join(outDir, imageId));
    return {
      imageId,
      src,
      alt: raw.alt || selection.alt || "",
      caption: selection.caption || raw.caption || "",
      relevanceScore: selection.relevanceScore,
      apCategory: selection.apCategory,
      description: selection.description,
      apThemes: selection.apThemes,
      period: PERIOD_ID,
      suggestedUse: selection.suggestedUse || ["notes", "mcq-stimulus", "saq-stimulus", "flashcard"],
    };
  });
}

function makeTimelineEvent(spec, event) {
  const eventId = event.id || id(spec.chapterNum, slugify(event.title));
  return {
    id: eventId,
    chapterId: spec.chapterId,
    periodId: PERIOD_ID,
    year: event.year,
    month: event.month ?? null,
    title: event.title,
    summary: event.summary,
    fullDescription: event.fullDescription,
    categories: event.categories,
    apThemes: event.apThemes,
    keyFigures: event.keyFigures || [],
    causes: event.causes || [],
    effects: event.effects || [],
    connectedEventIds: event.connectedEventIds || [],
    significance: event.significance || "Medium",
    apPriority: event.apPriority === true,
    essayRelevance: event.essayRelevance || "",
    commonMisconception: event.commonMisconception || "",
    imageId: event.imageId || null,
  };
}

function makePeriodEvent(spec, event) {
  return {
    id: event.id,
    chapterId: spec.chapterId,
    periodId: PERIOD_ID,
    year: event.year,
    title: event.title,
    summary: event.summary.split(". ")[0].replace(/\.$/, "") + ".",
    categories: event.categories,
    apPriority: true,
    significance: event.essayRelevance || event.summary,
    imageId: event.imageId || null,
  };
}

function makeMcqs(spec, images) {
  const questions = [];
  const facts = spec.mcqFacts;
  const textStimuli = spec.textStimuli;

  for (let i = 1; i <= 50; i += 1) {
    const fact = facts[(i - 1) % facts.length];
    const difficulty = i <= 12 ? "Easy" : i <= 32 ? "Medium" : "Hard";
    const isImage = i <= 8;
    const isText = i > 8 && i <= 14;
    const image = images[(i - 1) % images.length];
    const textStimulus = textStimuli[(i - 9) % textStimuli.length];
    const stemVariant = i % 4;
    const question =
      stemVariant === 0
        ? `Which development best explains the APUSH significance of ${fact.topic}?`
        : stemVariant === 1
          ? `The historical development associated with ${fact.topic} most directly contributed to which of the following?`
          : stemVariant === 2
            ? `Which claim would be best supported by evidence about ${fact.topic}?`
            : `A historian studying ${fact.topic} would most likely connect it to which broader trend?`;

    questions.push({
      id: `${spec.chapterId}-mcq-${String(i).padStart(3, "0")}`,
      chapterId: spec.chapterId,
      difficulty,
      apSkill: fact.skill || (i % 5 === 0 ? "Comparison" : i % 3 === 0 ? "Continuity and Change Over Time" : "Causation"),
      stimulusType: isImage ? "image" : isText ? "text" : null,
      stimulusImageId: isImage ? image.imageId : null,
      stimulusText: isText ? textStimulus.text : null,
      stimulusCaption: isImage ? image.caption : isText ? textStimulus.caption : null,
      question,
      options: {
        A: fact.correct,
        B: fact.wrong[0],
        C: fact.wrong[1],
        D: fact.wrong[2],
      },
      correctAnswer: "A",
      explanation: {
        correct: fact.explanation,
        wrongB: `This is plausible because it uses period language, but it misidentifies the central cause or consequence of ${fact.topic}.`,
        wrongC: `This choice points to a real APUSH theme, but it belongs more directly to another period or to a different development in the chapter.`,
        wrongD: `This answer overstates, reverses, or ignores the main historical relationship tested by the question.`,
      },
      topicTag: fact.topic,
      apTheme: fact.theme,
    });
  }

  return questions;
}

function makeSaq(spec, images) {
  return spec.saqPrompts.map((prompt, index) => {
    const image = images[index % images.length];
    const textStimulus = spec.textStimuli[index % spec.textStimuli.length];
    const stimulusType = index < 3 ? "image" : index < 6 ? "text" : "none";
    return {
      id: `${spec.chapterId}-saq-${String(index + 1).padStart(3, "0")}`,
      chapterId: spec.chapterId,
      stimulusType,
      stimulusImageId: stimulusType === "image" ? image.imageId : null,
      stimulusText: stimulusType === "text" ? textStimulus.text : null,
      stimulusCaption: stimulusType === "image" ? image.caption : stimulusType === "text" ? textStimulus.caption : null,
      prompt: prompt.prompt,
      partA: prompt.partA,
      partB: prompt.partB,
      partC: prompt.partC,
      scoringGuidance: prompt.scoringGuidance,
      sampleAnswers: prompt.sampleAnswers,
    };
  });
}

function makeFlashcards(spec, images, timeline) {
  const cards = [];
  let count = 1;
  const add = (type, front, back, hint, imageId, difficulty = "Medium", apPriority = true) => {
    cards.push({
      id: `${spec.chapterId}-fc-${String(count).padStart(3, "0")}`,
      chapterId: spec.chapterId,
      type,
      front,
      back,
      hint,
      imageId: imageId || null,
      periodId: PERIOD_ID,
      difficulty,
      apPriority,
    });
    count += 1;
  };

  for (const term of spec.vocabulary) add("Term", term.term, `${term.definition} ${term.apRelevance}`, term.context, null, "Easy", true);
  for (const figure of spec.keyFigures) add("Person", figure.name, `${figure.title}: ${figure.bio} ${figure.significance}`, figure.perspective, figure.imageId, "Medium", true);
  for (const event of timeline.slice(0, 12)) add("Event", event.title, `${event.year}: ${event.summary} ${event.essayRelevance}`, event.commonMisconception || "Link this event to a larger APUSH theme.", event.imageId, event.apPriority ? "Medium" : "Easy", event.apPriority);
  for (const item of spec.conceptCards) add(item.type, item.front, item.back, item.hint, null, item.difficulty || "Hard", item.apPriority !== false);
  for (const image of images.filter((img) => img.relevanceScore >= 4)) {
    add("Visual", "What does this image show and why is it significant?", image.description, image.caption, image.imageId, "Medium", true);
  }

  while (cards.length < 40) {
    const event = timeline[(cards.length - spec.vocabulary.length) % timeline.length];
    add("Cause-Effect", `What caused and resulted from ${event.title}?`, `Causes included ${event.causes.join(", ")}. Effects included ${event.effects.join(", ")}.`, event.essayRelevance, event.imageId, "Medium", event.apPriority);
  }

  return cards;
}

function buildChapter(spec) {
  const images = materializeImages(spec);
  const imageIds = images.map((image) => image.imageId);
  const timeline = spec.timeline.map((event) => makeTimelineEvent(spec, { ...event, imageId: event.imageIndex ? imageIds[event.imageIndex - 1] : event.imageId || null }));
  const highPriorityEvents = timeline.filter((event) => event.apPriority && event.significance === "High").slice(0, 5);

  const data = {
    chapterId: spec.chapterId,
    chapterNum: spec.chapterNum,
    periodId: PERIOD_ID,
    chapterOrder: spec.chapterOrder,
    images,
    chapterMeta: spec.chapterMeta,
    notes: spec.notes(imageIds),
    chapterTimeline: timeline,
    periodTimelineEvents: highPriorityEvents.map((event) => makePeriodEvent(spec, event)),
    periodTimeline: timeline,
    vocabulary: spec.vocabulary,
    essayPractice: {
      saq: makeSaq(spec, images),
      leq: spec.leq,
      dbq: spec.dbq(imageIds),
    },
    mcqQuestions: makeMcqs(spec, images),
    flashcards: makeFlashcards(spec, images, timeline),
  };

  fs.writeFileSync(path.join(ROOT, `chapter${spec.chapterNum}-data.js`), `window.chapter${spec.chapterNum}Data = ${JSON.stringify(data, null, 2)};\n`);
  return data;
}

