function factObjects(rawFacts, explanations) {
  return rawFacts.map(([topic, correct, [theme]]) => ({
    topic,
    correct,
    wrong: [
      "The federal government retreated completely from international and domestic commitments.",
      "Most Americans rejected consumer capitalism and demanded a return to preindustrial localism.",
      "The Supreme Court and Congress immediately eliminated all racial and economic inequality.",
    ],
    explanation: explanations[topic] || correct,
    theme,
  }));
}

const commonWrong = (text) => [
  "It shows that isolationism became the dominant national policy after World War II.",
  "It proves that reform movements ended once legal victories were announced.",
  "It indicates that economic growth benefited every racial and regional group equally.",
];

function makeFact(topic, correct, theme, explanation, wrong = commonWrong()) {
  return { topic, correct, wrong, explanation, theme };
}

