    leq: [
      { id: "chapter25-leq-001", chapterId: "chapter25", prompt: "Evaluate the extent to which liberal reform transformed the United States from 1960 to 1968.", recommendedArgument: "Continuity and Change Over Time", thesisExamples: ["Liberal reform transformed the United States through civil rights laws, voting rights, Medicare, Medicaid, and antipoverty programs, but it did not eliminate racial inequality and was weakened by Vietnam and conservative backlash.", "The 1960s marked the high point of New Deal liberalism because Johnson expanded federal responsibility, yet the persistence of urban unrest and the war in Vietnam exposed limits to that transformation."], outlineScaffold: { contextualization: "Discuss New Deal liberalism, postwar affluence, civil rights activism, and Cold War politics.", bodyParagraph1: { claim: "Civil rights reform transformed law and politics.", evidence: ["Civil Rights Act of 1964", "Voting Rights Act of 1965"], analysis: "Federal power directly attacked Jim Crow and disfranchisement." }, bodyParagraph2: { claim: "Great Society programs expanded the welfare state.", evidence: ["Medicare", "Medicaid", "War on Poverty"], analysis: "Johnson continued and enlarged New Deal ideas of federal responsibility." }, bodyParagraph3: { claim: "Limits and backlash constrained reform.", evidence: ["Vietnam War", "Urban uprisings", "Goldwater campaign"], analysis: "War and disorder divided the coalition needed for reform." }, complexity: "Show that reform was legally transformative but socially incomplete." }, scoringRubric: { thesis: "1 point - Defensible claim about transformation.", contextualization: "1 point - Establishes New Deal and civil rights background.", evidence: "2 points - Uses laws, programs, and backlash examples.", analysis: "2 points - Applies CCOT or causation.", complexity: "1 point - Balances achievements with limits." } },
      { id: "chapter25-leq-002", chapterId: "chapter25", prompt: "Evaluate the extent to which the Vietnam War caused political and cultural conflict in the United States from 1964 to 1968.", recommendedArgument: "Causation", thesisExamples: ["Vietnam was a major cause of political and cultural conflict because it expanded executive power, fueled student protest, split Democrats, and weakened trust in government, although racial conflict and rights movements also independently contributed to unrest.", "The Vietnam War fractured Cold War liberalism by turning many young activists against the government and draining support for the Great Society, but it interacted with broader conflicts over race, gender, and authority."], outlineScaffold: { contextualization: "Explain containment, Korea, Kennedy's Cold War policies, and early 1960s activism.", bodyParagraph1: { claim: "Vietnam escalated political conflict over executive power.", evidence: ["Gulf of Tonkin Resolution", "Johnson escalation"], analysis: "The war raised questions about presidential authority and credibility." }, bodyParagraph2: { claim: "Vietnam fueled cultural and student protest.", evidence: ["SDS", "Pentagon protest", "draft resistance"], analysis: "Students connected the war to bureaucracy and moral hypocrisy." }, bodyParagraph3: { claim: "Vietnam interacted with other sources of conflict.", evidence: ["Civil rights movement", "urban uprisings", "Black Power"], analysis: "Not all unrest came from Vietnam, but the war intensified distrust and backlash." }, complexity: "Argue that Vietnam was necessary to the scale of conflict but not sufficient to explain all 1960s turmoil." }, scoringRubric: { thesis: "1 point - Defensible causal claim.", contextualization: "1 point - Establishes Cold War containment background.", evidence: "2 points - Uses specific Vietnam and domestic examples.", analysis: "2 points - Explains causal relationships.", complexity: "1 point - Weighs Vietnam against other causes." } },
    ],
